import React from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css"; // Import styles

const Navbar = () => {
  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <Link to="HOME" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </Link>
      </div>
      <ul className="navbar-links">
        {[
          "HOME",
          "ABOUT US",
          "AREAS OF PRACTICE",
          "OUR PROFESSIONALS",
          "NEWS & ARTICLES",
          "GALLERY",
          "CONTACT US", // Fixed typo from "COUNTACT US"
        ].map((section) => (
          <li key={section}>
            <Link
              to={section} 
              smooth={true} 
              duration={500} 
              activeClass="active"
              spy={true} // Helps in highlighting active section
              offset={-70} // Adjust this based on navbar height if needed
            >
              {section.replace(/^\w/, (c) => c.toUpperCase()).replace("-", " ")}
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
